Add-Type -MemberDefinition '[DllImport("user32.dll")] public static extern void mouse_event(int dwFlags, int dx, int dy, int dwData, int dwExtraInfo);' -Name "MouseInput" -Namespace "Win32"; while ($true) { [Win32.MouseInput]::mouse_event(1,1,0,0,0); Start-Sleep -Milliseconds 50; [Win32.MouseInput]::mouse_event(1,-1,0,0,0); Write-Host ("[{0:yyyy-MM-dd HH:mm:ss}] moved" -f (Get-Date)); Start-Sleep -Seconds 30 }
